SELECT email
FROM teachers
WHERE teacher_id = 1;

SELECT MAX(student_count) AS max_students_in_major
FROM (
  SELECT major, COUNT(*) AS student_count
  FROM students
  GROUP BY major
) AS major_student_counts;

SELECT announcement_title, is_important
FROM announcements
ORDER BY announcement_date ASC;

SELECT course_name, PERCENT_RANK() OVER (ORDER BY course_id) as course_percent_rank
FROM courses
ORDER BY course_id;
